import anthropic
import requests


PAGERDUTY_TOKEN = os.environ["PAGERDUTY_TOKEN"]


def has_active_p0_p1() -> bool:
    """Return True if any P0 or P1 incident is currently triggered in PagerDuty."""
    resp = requests.get(
        "https://api.pagerduty.com/incidents",
        headers={
            "Authorization": f"Token token={PAGERDUTY_TOKEN}",
            "Accept": "application/vnd.pagerduty+json;version=2",
        },
        params={
            "statuses[]": ["triggered", "acknowledged"],
            "urgencies[]": ["high"],
        },
        timeout=10,
    )
    resp.raise_for_status()
    return len(resp.json().get("incidents", [])) > 0


def pre_experiment_gate() -> None:
    if has_active_p0_p1():
        raise RuntimeError(
            "CHAOS ABORTED: active P0/P1 incident in PagerDuty. "
            "Resolve all incidents before running experiments."
        )

import requests


def query_prometheus(expr: str, url: str = PROMETHEUS_URL) -> float:
    resp = requests.get(
        f"{url}/api/v1/query", params={"query": expr}, timeout=10
    )
    resp.raise_for_status()
    results = resp.json()["data"]["result"]
    return float(results[0]["value"][1]) if results else 0.0


def baseline_health_gate() -> None:
    error_rate = query_prometheus(
        'sum(rate(claude_api_errors_total[5m])) / sum(rate(claude_api_requests_total[5m]))'
    )
    if error_rate > 0.005:
        raise RuntimeError(
            f"CHAOS ABORTED: baseline error rate {error_rate:.3%} exceeds 0.5%. "
            "System already degraded."
        )

    p99 = query_prometheus(
        'histogram_quantile(0.99, rate(claude_api_duration_seconds_bucket[5m]))'
    )
    SLO_P99 = float(os.environ.get("SLO_P99_SECONDS", "2.0"))
    if p99 > 2 * SLO_P99:
        raise RuntimeError(
            f"CHAOS ABORTED: p99 latency {p99:.2f}s exceeds 2× SLO ({2*SLO_P99:.2f}s)"
        )

    queue_depth = query_prometheus('claude_worker_queue_depth')
    MAX_QUEUE = float(os.environ.get("MAX_QUEUE_DEPTH", "1000"))
    if queue_depth > 0.8 * MAX_QUEUE:
        raise RuntimeError(
            f"CHAOS ABORTED: queue depth {queue_depth:.0f} > 80% of capacity {MAX_QUEUE:.0f}"
        )
